package com.taskflow.entity;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.time.LocalDateTime;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("Task Entity")
class TaskTest {

    @Test
    @DisplayName("should have null id before persistence")
    void shouldHaveNullIdBeforePersistence() {
        Task task = new Task();
        assertThat(task.getId()).isNull();
    }

    @Test
    @DisplayName("should create Task with all required fields")
    void shouldCreateTaskWithAllRequiredFields() {
        Task task = new Task();
        task.setTitle("Test Task");
        task.setDescription("A test description");
        task.setPriority("MEDIUM");
        task.setStatus(TaskStatus.TODO);
        task.setCreatedBy(1L);

        assertThat(task.getTitle()).isEqualTo("Test Task");
        assertThat(task.getDescription()).isEqualTo("A test description");
        assertThat(task.getPriority()).isEqualTo("MEDIUM");
        assertThat(task.getStatus()).isEqualTo(TaskStatus.TODO);
        assertThat(task.getCreatedBy()).isEqualTo(1L);
    }

    @Test
    @DisplayName("should default status to TODO")
    void shouldDefaultStatusToTodo() {
        Task task = new Task();
        assertThat(task.getStatus()).isEqualTo(TaskStatus.TODO);
    }

    @Test
    @DisplayName("should default priority to MEDIUM")
    void shouldDefaultPriorityToMedium() {
        Task task = new Task();
        assertThat(task.getPriority()).isEqualTo("MEDIUM");
    }

    @Test
    @DisplayName("should default deleted to false")
    void shouldDefaultDeletedToFalse() {
        Task task = new Task();
        assertThat(task.isDeleted()).isFalse();
    }

    @Test
    @DisplayName("should have createdAt and updatedAt fields")
    void shouldHaveTimestampFields() {
        Task task = new Task();
        LocalDateTime now = LocalDateTime.now();
        task.setCreatedAt(now);
        task.setUpdatedAt(now);

        assertThat(task.getCreatedAt()).isEqualTo(now);
        assertThat(task.getUpdatedAt()).isEqualTo(now);
    }

    @Test
    @DisplayName("should accept title up to 200 characters")
    void shouldAcceptTitleUpTo200Characters() {
        Task task = new Task();
        String title200 = "A".repeat(200);
        task.setTitle(title200);
        assertThat(task.getTitle()).hasSize(200);
    }

    @Test
    @DisplayName("should accept description up to 5000 characters")
    void shouldAcceptDescriptionUpTo5000Characters() {
        Task task = new Task();
        String desc5000 = "B".repeat(5000);
        task.setDescription(desc5000);
        assertThat(task.getDescription()).hasSize(5000);
    }

    @Test
    @DisplayName("should set and get deleted flag")
    void shouldSetAndGetDeletedFlag() {
        Task task = new Task();
        task.setDeleted(true);
        assertThat(task.isDeleted()).isTrue();
    }
}

