    @Test
    @DisplayName("should have description field")
    void shouldHaveDescriptionField() {
        TaskResponse response = new TaskResponse();
        response.setDescription("A description");
        assertThat(response.getDescription()).isEqualTo("A description");
    }

    @Test
    @DisplayName("should have priority field")
    void shouldHavePriorityField() {
        TaskResponse response = new TaskResponse();
        response.setPriority("HIGH");
        assertThat(response.getPriority()).isEqualTo("HIGH");
    }

    @Test
    @DisplayName("should have status field")
    void shouldHaveStatusField() {
        TaskResponse response = new TaskResponse();
        response.setStatus("TODO");
        assertThat(response.getStatus()).isEqualTo("TODO");
    }

    @Test
    @DisplayName("should have createdBy field")
    void shouldHaveCreatedByField() {
        TaskResponse response = new TaskResponse();
        response.setCreatedBy(42L);
        assertThat(response.getCreatedBy()).isEqualTo(42L);
    }

    @Test
    @DisplayName("should have createdAt field")
    void shouldHaveCreatedAtField() {
        TaskResponse response = new TaskResponse();
        LocalDateTime now = LocalDateTime.now();
        response.setCreatedAt(now);
        assertThat(response.getCreatedAt()).isEqualTo(now);
